def en_uzun_ardisik_dizi(sayilar):
    if not sayilar:
        return 0
    en_uzun = 1
    guncel = 1
    for i in range(1, len(sayilar)):
        if sayilar[i] == sayilar[i - 1]:
            guncel += 1
            en_uzun = max(en_uzun, guncel)
        else:
            guncel = 1
    return en_uzun
